(window.webpackJsonp=window.webpackJsonp||[]).push([[375],{1002:function(r,n){r.exports="\x3c!-- \r\ntitle: 02-第二节课\r\nsort: \r\n--\x3e \r\n\r\n> 上一节内容的扩展\r\n\r\n- [ ] 我为什么使用Linux?\r\n- [ ] 如何记笔记?\r\n- [ ] 基础Linux命令\r\n  - 文件管理\r\n  - 权限\r\n- [ ] vim操作技巧\r\n\r\n## 为什么使用Linux\r\n\r\n> 让同学们对Linux感兴趣\r\n>\r\n> 演示使用manjaro+i3wm\r\n\r\n### Win10\r\n\r\n> 糟糕窗口管理\r\n>\r\n> 系统比Linux大几十倍\r\n>\r\n> 但开发者常用工具并不内置\r\n>\r\n> 安装软件糟糕的体验(下一步..下一步..下一步)\r\n\r\n### Linux\r\n\r\n> 快捷窗口管理\r\n>\r\n> 安装软件只需一行命令,并且不用考虑放在c盘还是d盘.\r\n>\r\n> 无须到处翻找乱七八糟的应用\r\n\r\n## 如何记笔记\r\n\r\n> 参考我这篇\r\n\r\n## Linux基础命令\r\n\r\n- `ls`\r\n\r\n  > -a: 显示隐藏文件\r\n  >\r\n  > -l: 长格式列出信息\r\n  >\r\n  > `ls | grep test`\r\n\r\n  ```bash\r\n  ls -l\r\n  drwxr-xr-x   4 fzf fzf   4096 11月 20 10:53 C\r\n  # 一个目录\r\n  drwxr-xr-x\t[文件类型 d目录] [权限->用户|组|其他] \r\n  4 fzf fzf\t[内部文件数] [所属用户] [所属组] \r\n  4096 11月 20 10:53 C\t[文件大小 目录皆为4096] [修改时间] [文件名]\r\n  \r\n  -rwxrwxr-x  1 fzf  fzf      194 11月 16 17:07 demo.c\r\n  # 一个文件020-03-10 16\r\n  -rwxrwxr-x\t[文件类型 -文件] [权限->用户|组|其他] \r\n  4 fzf fzf\t[链接数] [所属用户] [所属组] \r\n  4096 11月 20 10:53 C\t[文件大小 目录皆为4096] [修改时间] [文件名]\r\n  ```\r\n\r\n- `cd`\r\n\r\n  > change dir\t切换目录\r\n\r\n- `mkdir <dir1> <dir2>...`\r\n\r\n  > 新建目录\r\n\r\n- `cat`\r\n\r\n  > 把文件内容打印到标准输出\r\n\r\n- `mv`\r\n\r\n  > 移动文件 {or 改名}\r\n\r\n- `rm`\r\n\r\n  > 删除文件\r\n  >\r\n  > -r: 递归删除\r\n  >\r\n  > -f: 强制删除\r\n\r\n- `cp`\r\n\r\n  > 复制\r\n  >\r\n  > 参数说明同上\r\n\r\n- `chmod`\r\n\r\n  > 设置权限\r\n  >\r\n  > `chmod u/g/o -/+ r/w/x  [file]`\r\n  >\r\n  > u/g/o: 用户 组 其他\r\n  >\r\n  > -/+: 去掉/增加权限\r\n  >\r\n  > r/w/x: 读/写/运行\r\n  >\r\n  > `chmod u+w demo`: 为demo所属用户+w权限\r\n  >\r\n  > 775下回讲\r\n\r\n## Vim\r\n\r\n| 命令                     | 功能                                                   |\r\n| ------------------------ | ------------------------------------------------------ |\r\n| y<br />[number] yy       | 复制<br />复制n行                                      |\r\n| p                        | 粘贴                                                   |\r\n| iI/aA/oO                 | 插入+行首/当前字符+末尾/下一行+上一行                  |\r\n| c<br />ciw<br />cf[char] | change<br />修改当前光标下的word<br />修改到第一个char |\r\n\r\n "}}]);